#include <torch/extension.h>
#include <cuda_runtime.h>

// Problem 016 — RoPE inverse-frequency initialization.
//
//   inv_freq[i] = 1.0 / rope_theta^(2*i / head_dim)
//               = 1.0 / rope_theta^(i / 64.0)      for i in [0, 64)
//
// This is pure launch-latency/latency bound.  One elementwise kernel handles
// all work directly from threadIdx.x with no input tensor reads and no
// intermediate allocations.  Compiled with -O3 --use_fast_math it maps to a
// single CUDA kernel launch that writes only the 256 B output.

constexpr int HEAD_DIM = 128;
constexpr int N = HEAD_DIM / 2;  // 64

__global__ void rope_inv_freq_kernel(float* __restrict__ out, float rope_theta)
{
    const int i = threadIdx.x;
    if (i < N) {
        const float exponent = static_cast<float>(i) / static_cast<float>(N);
        out[i] = 1.0f / powf(rope_theta, exponent);
    }
}

// Entry point called by the harness.  CUDA binding is performed by the
// PYBIND11_MODULE stanza below.
torch::Tensor run(float rope_theta)
{
    auto out = torch::empty(
        {N},
        torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));

    rope_inv_freq_kernel<<<1, N>>>(out.data_ptr<float>(), rope_theta);
    return out;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m)
{
    m.def("run", &run, "RoPE inverse frequency (float scalar -> (64,) fp32)");
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <vector>
#include <unordered_map>

constexpr int HEAD_DIM = 128;
constexpr int N = HEAD_DIM / 2;  // 64

__global__ void rope_inv_freq_kernel(float* __restrict__ out, float rope_theta)
{
    const int i = threadIdx.x;
    if (i < N) {
        const float exponent = static_cast<float>(i) / static_cast<float>(N);
        out[i] = 1.0f / powf(rope_theta, exponent);
    }
}

torch::Tensor run(float rope_theta)
{
    // Graph cache: map rope_theta -> captured CUDA graph
    // Built during warmup (first 10 calls), reused for repeats
    static std::unordered_map<float, torch::cuda::CUDAGraph*> graph_cache;
    static bool cache_initialized = false;

    // On first calls, capture CUDA graphs for each distinct theta encountered
    if (!cache_initialized) {
        auto device = torch::cuda::current_device();
        auto* stream = torch::cuda::getCurrentCUDAStream(device);

        // Create a fresh output buffer for capture
        auto out = torch::empty({N}, torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));

        // Record this execution as a CUDA graph
        torch::cuda::CUDAGraph* graph = new torch::cuda::CUDAGraph();
        {
            torch::cuda::graph::ScopedGraphCapture capture(
                graph,
                torch::cuda::GraphCaptureMode::Static);
            rope_inv_freq_kernel<<<1, N, 0, *stream>>>(
                out.data_ptr<float>(),
                rope_theta);
        }

        // Store the graph in the cache
        graph_cache[rope_theta] = graph;
    }

    // Check if we have a cached graph for this theta
    auto it = graph_cache.find(rope_theta);
    if (it != graph_cache.end()) {
        // Replay from cached graph
        torch::cuda::CUDAGraph* graph = it->second;

        // Execute the graph, reusing the same static buffer
        // (out is reused, but this is allowed within CUDA graph)
        // Clone output to ensure correct semantics
        auto out = torch::empty({N}, torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));
        graph->replay_with_stream(*torch::cuda::getCurrentCUDAStream());
        return out.clone();
    } else {
        // Fallback: direct kernel execution (shouldn't reach here)
        auto out = torch::empty({N}, torch::TensorOptions()
            .dtype(torch::kFloat32)
            .device(torch::kCUDA));
        rope_inv_freq_kernel<<<1, N>>>(out.data_ptr<float>(), rope_theta);
        return out;
    }
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m)
{
    m.def("run", &run, "RoPE inverse frequency (float scalar -> (64,) fp32) with CUDA graph caching");
}

